231	JSContext *
232	qjs_new_context(JSRuntime *rt, qjs_module_t **addons)
233	{
234	    int           ret;
235	    JSAtom        prop;
236	    JSValue       global_obj;
237	    JSContext     *ctx;
238	    qjs_module_t  **module;
239	
240	    ctx = JS_NewContextRaw(rt);
241	    if (ctx == NULL) {
242	        return NULL;
243	    }
244	
245	    JS_AddIntrinsicBaseObjects(ctx);
246	    JS_AddIntrinsicDate(ctx);
247	    JS_AddIntrinsicRegExp(ctx);
248	    JS_AddIntrinsicJSON(ctx);
249	    JS_AddIntrinsicProxy(ctx);
250	    JS_AddIntrinsicMapSet(ctx);
251	    JS_AddIntrinsicTypedArrays(ctx);
252	    JS_AddIntrinsicPromise(ctx);
253	#ifdef NJS_HAVE_QUICKJS_ADD_INTRINSIC_BIG_INT
254	    JS_AddIntrinsicBigInt(ctx);
255	#endif
256	    JS_AddIntrinsicEval(ctx);
257	
258	    for (module = qjs_modules; *module != NULL; module++) {
259	        if ((*module)->init(ctx, (*module)->name) == NULL) {
260	            return NULL;
261	        }
262	    }
263	
264	    if (addons != NULL) {
265	        for (module = addons; *module != NULL; module++) {
266	            if ((*module)->init(ctx, (*module)->name) == NULL) {
267	                return NULL;
268	            }
269	        }
270	    }
271	
272	    global_obj = JS_GetGlobalObject(ctx);
273	
274	    if (qjs_add_intrinsic_njs(ctx, global_obj) < 0) {
275	        return NULL;
276	    }
277	
278	    if (qjs_add_intrinsic_text_decoder(ctx, global_obj) < 0) {
279	        return NULL;
280	    }
281	
282	    if (qjs_add_intrinsic_text_encoder(ctx, global_obj) < 0) {
283	        return NULL;
284	    }
285	
286	    if (qjs_add_intrinsic_btoa_atob(ctx, global_obj) < 0) {
287	        return NULL;
288	    }
289	
290	    prop = JS_NewAtom(ctx, "eval");
291	    if (prop == JS_ATOM_NULL) {
292	        return NULL;
293	    }
294	
295	    ret = JS_DeleteProperty(ctx, global_obj, prop, 0);
296	    JS_FreeAtom(ctx, prop);
297	    if (ret < 0) {
298	        return NULL;
299	    }
300	
301	    prop = JS_NewAtom(ctx, "Function");
302	    if (prop == JS_ATOM_NULL) {
303	        return NULL;
304	    }
305	
306	    ret = JS_DeleteProperty(ctx, global_obj, prop, 0);
307	    JS_FreeAtom(ctx, prop);
308	    if (ret < 0) {
309	        return NULL;
310	    }
311	
312	    JS_FreeValue(ctx, global_obj);
313	
314	    return ctx;
315	}
