318	JSValue
319	qjs_call_exit_hook(JSContext *ctx)
320	{
321	    JSValue    global, obj, ret;
322	    qjs_njs_t  *njs;
323	
324	    global = JS_GetGlobalObject(ctx);
325	
326	    obj = JS_GetPropertyStr(ctx, global, "njs");
327	    if (JS_IsException(obj) || JS_IsUndefined(obj)) {
328	        goto done;
329	    }
330	
331	    njs = JS_GetOpaque(obj, QJS_CORE_CLASS_ID_NJS);
332	    if (njs != NULL && JS_IsFunction(ctx, njs->hooks[QJS_NJS_HOOK_EXIT])) {
333	        ret = JS_Call(ctx, njs->hooks[QJS_NJS_HOOK_EXIT], JS_UNDEFINED,
334	                      0, NULL);
335	
336	        JS_FreeValue(ctx, njs->hooks[QJS_NJS_HOOK_EXIT]);
337	        njs->hooks[QJS_NJS_HOOK_EXIT] = JS_UNDEFINED;
338	
339	        if (JS_IsException(ret)) {
340	            JS_FreeValue(ctx, obj);
341	            JS_FreeValue(ctx, global);
342	            return ret;
343	        }
344	
345	        JS_FreeValue(ctx, ret);
346	    }
347	
348	done:
349	
350	    JS_FreeValue(ctx, obj);
351	    JS_FreeValue(ctx, global);
352	
353	    return JS_UNDEFINED;
354	}
