423	static JSValue
424	qjs_njs_on(JSContext *ctx, JSValueConst this_val, int argc,
425	    JSValueConst *argv)
426	{
427	    unsigned   i, n;
428	    qjs_njs_t  *njs;
429	    njs_str_t  name;
430	
431	    static const njs_str_t hooks[] = {
432	        njs_str("exit"),
433	    };
434	
435	    njs = JS_GetOpaque(this_val, QJS_CORE_CLASS_ID_NJS);
436	    if (njs == NULL) {
437	        njs = js_mallocz(ctx, sizeof(qjs_njs_t));
438	        if (njs == NULL) {
439	            return JS_ThrowOutOfMemory(ctx);
440	        }
441	
442	        JS_SetOpaque(this_val, njs);
443	    }
444	
445	    name.start = (u_char *) JS_ToCStringLen(ctx, &name.length, argv[0]);
446	    if (name.start == NULL) {
447	        return JS_EXCEPTION;
448	    }
449	
450	    i = 0;
451	    n = njs_nitems(hooks);
452	
453	    while (i < n) {
454	        if (njs_strstr_eq(&name, &hooks[i])) {
455	            break;
456	        }
457	
458	        i++;
459	    }
460	
461	    if (i == n) {
462	        JS_ThrowTypeError(ctx, "unknown hook \"%s\"", name.start);
463	        JS_FreeCString(ctx, (const char *) name.start);
464	        return JS_EXCEPTION;
465	    }
466	
467	    JS_FreeCString(ctx, (const char *) name.start);
468	
469	    if (!JS_IsFunction(ctx, argv[1]) && !JS_IsNull(argv[1])) {
470	        JS_ThrowTypeError(ctx, "callback is not a function or null");
471	        return JS_EXCEPTION;
472	    }
473	
474	    JS_FreeValue(ctx, njs->hooks[i]);
475	    njs->hooks[i] = JS_DupValue(ctx, argv[1]);
476	
477	    return JS_UNDEFINED;
478	}
