481	static JSValue
482	qjs_process_env(JSContext *ctx, JSValueConst this_val)
483	{
484	    int         ret;
485	    char        **ep;
486	    JSValue     obj;
487	    JSAtom      atom;
488	    JSValue     str, name;
489	    const char  *entry, *value;
490	
491	    obj = JS_NewObject(ctx);
492	    if (JS_IsException(obj)) {
493	        return JS_EXCEPTION;
494	    }
495	
496	    ep = environ;
497	
498	    while (*ep != NULL) {
499	        entry = *ep++;
500	
501	        value = (const char *) njs_strchr(entry, '=');
502	        if (value == NULL) {
503	            continue;
504	        }
505	
506	        str = JS_UNDEFINED;
507	        name = JS_NewStringLen(ctx, entry, value - entry);
508	        if (JS_IsException(name)) {
509	            goto error;
510	        }
511	
512	        value++;
513	
514	        str = JS_NewStringLen(ctx, value, njs_strlen(value));
515	        if (JS_IsException(str)) {
516	            goto error;
517	        }
518	
519	        atom = JS_ValueToAtom(ctx, name);
520	        if (atom == JS_ATOM_NULL) {
521	            goto error;
522	        }
523	
524	        ret = JS_DefinePropertyValue(ctx, obj, atom, str, JS_PROP_C_W_E);
525	        JS_FreeAtom(ctx, atom);
526	        if (ret < 0) {
527	            str = JS_UNDEFINED;
528	            goto error;
529	        }
530	
531	        JS_FreeValue(ctx, name);
532	    }
533	
534	    return obj;
535	
536	error:
537	
538	    JS_FreeValue(ctx, name);
539	    JS_FreeValue(ctx, str);
540	    JS_FreeValue(ctx, obj);
541	
542	    return JS_EXCEPTION;
543	}
