545	
546	static JSValue
547	qjs_process_kill(JSContext *ctx, JSValueConst this_val, int argc,
548	    JSValueConst *argv)
549	{
550	    int                 signo, pid;
551	    JSValue             ret;
552	    njs_str_t           name;
553	    const char          *signal;
554	    qjs_signal_entry_t  *entry;
555	
556	    if (JS_ToInt32(ctx, &pid, argv[0]) < 0) {
557	        return JS_EXCEPTION;
558	    }
559	
560	    signo = SIGTERM;
561	
562	    if (JS_IsNumber(argv[1])) {
563	        if (JS_ToInt32(ctx, &signo, argv[1]) < 0) {
564	            return JS_EXCEPTION;
565	        }
566	
567	        if (signo < 0 || signo >= NSIG) {
568	            return JS_ThrowTypeError(ctx, "unknown signal: %d", signo);
569	        }
570	
571	    } else {
572	        signal = JS_ToCString(ctx, argv[1]);
573	        if (signal == NULL) {
574	            return JS_EXCEPTION;
575	        }
576	
577	        if (njs_strlen(signal) < 3 || memcmp(signal, "SIG", 3) != 0) {
578	            ret = JS_ThrowTypeError(ctx, "unknown signal: %s", signal);
579	            JS_FreeCString(ctx, signal);
580	            return ret;
581	        }
582	
583	        name.start = (u_char *) signal + 3;
584	        name.length = njs_strlen(signal) - 3;
585	
586	        for (entry = qjs_signals_table; entry->name.length != 0; entry++) {
587	            if (njs_strstr_eq(&entry->name, &name)) {
588	                signo = entry->value;
589	                break;
590	            }
591	        }
592	
593	        if (entry->name.length == 0) {
594	            ret = JS_ThrowTypeError(ctx, "unknown signal: %s", signal);
595	            JS_FreeCString(ctx, signal);
596	            return ret;
597	        }
598	
599	        JS_FreeCString(ctx, signal);
600	    }
601	
602	    if (kill(pid, signo) < 0) {
603	        return JS_ThrowTypeError(ctx, "kill failed with (%d:%s)", errno,
604	                                 strerror(errno));
605	    }
606	
607	    return JS_TRUE;
608	}
