806	static JSValue
807	qjs_text_decoder_decode(JSContext *cx, JSValueConst this_val, int argc,
808	    JSValueConst *argv)
809	{
810	    int                   stream;
811	    size_t                size;
812	    u_char                *dst;
813	    JSValue               ret;
814	    ssize_t               length;
815	    njs_str_t             data;
816	    const u_char          *end;
817	    qjs_text_decoder_t    *td;
818	    njs_unicode_decode_t  ctx;
819	
820	    td = JS_GetOpaque(this_val, QJS_CORE_CLASS_ID_TEXT_DECODER);
821	    if (td == NULL) {
822	        return JS_ThrowTypeError(cx, "'this' is not a TextDecoder");
823	    }
824	
825	    ret = qjs_typed_array_data(cx, argv[0], &data);
826	    if (JS_IsException(ret)) {
827	        return ret;
828	    }
829	
830	    stream = 0;
831	
832	    if (argc > 1) {
833	        ret = JS_GetPropertyStr(cx, argv[1], "stream");
834	        if (JS_IsException(ret)) {
835	            return JS_EXCEPTION;
836	        }
837	
838	        stream = JS_ToBool(cx, ret);
839	        JS_FreeValue(cx, ret);
840	    }
841	
842	    ctx = td->ctx;
843	    end = data.start + data.length;
844	
845	    if (data.start != NULL && !td->ignore_bom) {
846	        data.start += njs_utf8_bom(data.start, end);
847	    }
848	
849	    length = njs_utf8_stream_length(&ctx, data.start, end - data.start, !stream,
850	                                    td->fatal, &size);
851	
852	    if (length == -1) {
853	        return JS_ThrowTypeError(cx, "The encoded data was not valid");
854	    }
855	
856	    dst = js_malloc(cx, size + 1);
857	    if (dst == NULL) {
858	        JS_ThrowOutOfMemory(cx);
859	        return JS_EXCEPTION;
860	    }
861	
862	    (void) njs_utf8_stream_encode(&td->ctx, data.start, end, dst, !stream, 0);
863	
864	    ret = JS_NewStringLen(cx, (const char *) dst, size);
865	    js_free(cx, dst);
866	
867	    if (!stream) {
868	        njs_utf8_decode_init(&td->ctx);
869	    }
870	
871	    return ret;
872	}
