1051	qjs_text_encoder_encode_into(JSContext *cx, JSValueConst this_val, int argc,
1052	    JSValueConst *argv)
1053	{
1054	    int                   read, written;
1055	    void                  *te;
1056	    size_t                size;
1057	    u_char                *to, *to_end;
1058	    JSValue               ret;
1059	    uint32_t              cp;
1060	    njs_str_t             utf8, dst;
1061	    const u_char          *start, *end;
1062	    njs_unicode_decode_t  ctx;
1063	
1064	    te = JS_GetOpaque(this_val, QJS_CORE_CLASS_ID_TEXT_ENCODER);
1065	    if (te == NULL) {
1066	        return JS_ThrowTypeError(cx, "'this' is not a TextEncoder");
1067	    }
1068	
1069	    if (!JS_IsString(argv[0])) {
1070	        return JS_ThrowTypeError(cx, "The input argument must be a string");
1071	    }
1072	
1073	    ret = qjs_typed_array_data(cx, argv[1], &dst);
1074	    if (JS_IsException(ret)) {
1075	        return ret;
1076	    }
1077	
1078	    if (!qjs_is_uint8_array(cx, argv[1])) {
1079	        return JS_ThrowTypeError(cx, "The output argument must be a"
1080	                                 " Uint8Array");
1081	    }
1082	
1083	    utf8.start = (u_char *) JS_ToCStringLen(cx, &utf8.length, argv[0]);
1084	    if (utf8.start == NULL) {
1085	        return JS_EXCEPTION;
1086	    }
1087	
1088	    read = 0;
1089	    written = 0;
1090	
1091	    start = utf8.start;
1092	    end = start + utf8.length;
1093	
1094	    to = dst.start;
1095	    to_end = to + dst.length;
1096	
1097	    njs_utf8_decode_init(&ctx);
1098	
1099	    while (start < end) {
1100	        cp = njs_utf8_decode(&ctx, &start, end);
1101	
1102	        if (cp > NJS_UNICODE_MAX_CODEPOINT) {
1103	            cp = NJS_UNICODE_REPLACEMENT;
1104	        }
1105	
1106	        size = njs_utf8_size(cp);
1107	
1108	        if (to + size > to_end) {
1109	            break;
1110	        }
1111	
1112	        read += (cp > 0xFFFF) ? 2 : 1;
1113	        written += size;
1114	
1115	        to = njs_utf8_encode(to, cp);
1116	    }
1117	
1118	    JS_FreeCString(cx, (char *) utf8.start);
1119	
1120	    ret = JS_NewObject(cx);
1121	    if (JS_IsException(ret)) {
1122	        return ret;
1123	    }
1124	
1125	    if (JS_DefinePropertyValueStr(cx, ret, "read", JS_NewInt32(cx, read),
1126	                                  JS_PROP_C_W_E) < 0)
1127	    {
1128	        JS_FreeValue(cx, ret);
1129	        return JS_EXCEPTION;
1130	    }
1131	
1132	    if (JS_DefinePropertyValueStr(cx, ret, "written", JS_NewInt32(cx, written),
1133	                                  JS_PROP_C_W_E) < 0)
1134	    {
1135	        JS_FreeValue(cx, ret);
1136	        return JS_EXCEPTION;
1137	    }
1138	
1139	    return ret;
1140	}
