JSContext *
qjs_new_context(JSRuntime *rt, qjs_module_t **addons)
{
    int           ret;
    JSAtom        prop;
    JSValue       global_obj;
    JSContext     *ctx;
    qjs_module_t  **module;

    ctx = JS_NewContextRaw(rt);
    if (ctx == NULL) {
        return NULL;
    }

    JS_AddIntrinsicBaseObjects(ctx);
    JS_AddIntrinsicDate(ctx);
    JS_AddIntrinsicRegExp(ctx);
    JS_AddIntrinsicJSON(ctx);
    JS_AddIntrinsicProxy(ctx);
    JS_AddIntrinsicMapSet(ctx);
    JS_AddIntrinsicTypedArrays(ctx);
    JS_AddIntrinsicPromise(ctx);
#ifdef NJS_HAVE_QUICKJS_ADD_INTRINSIC_BIG_INT
    JS_AddIntrinsicBigInt(ctx);
#endif
    JS_AddIntrinsicEval(ctx);

    for (module = qjs_modules; *module != NULL; module++) {
        if ((*module)->init(ctx, (*module)->name) == NULL) {
            return NULL;
        }
    }

    if (addons != NULL) {
        for (module = addons; *module != NULL; module++) {
            if ((*module)->init(ctx, (*module)->name) == NULL) {
                return NULL;
            }
        }
    }

    global_obj = JS_GetGlobalObject(ctx);

    if (qjs_add_intrinsic_njs(ctx, global_obj) < 0) {
        return NULL;
    }

    if (qjs_add_intrinsic_text_decoder(ctx, global_obj) < 0) {
        return NULL;
    }

    if (qjs_add_intrinsic_text_encoder(ctx, global_obj) < 0) {
        return NULL;
    }

    if (qjs_add_intrinsic_btoa_atob(ctx, global_obj) < 0) {
        return NULL;
    }

    prop = JS_NewAtom(ctx, "eval");
    if (prop == JS_ATOM_NULL) {
        return NULL;
    }

    ret = JS_DeleteProperty(ctx, global_obj, prop, 0);
    JS_FreeAtom(ctx, prop);
    if (ret < 0) {
        return NULL;
    }

    prop = JS_NewAtom(ctx, "Function");
    if (prop == JS_ATOM_NULL) {
        return NULL;
    }

    ret = JS_DeleteProperty(ctx, global_obj, prop, 0);
    JS_FreeAtom(ctx, prop);
    if (ret < 0) {
        return NULL;
    }

    JS_FreeValue(ctx, global_obj);

    return ctx;
}


JSValue
qjs_call_exit_hook(JSContext *ctx)
{
    JSValue    global, obj, ret;
    qjs_njs_t  *njs;

    global = JS_GetGlobalObject(ctx);

    obj = JS_GetPropertyStr(ctx, global, "njs");
    if (JS_IsException(obj) || JS_IsUndefined(obj)) {
        goto done;
    }

    njs = JS_GetOpaque(obj, QJS_CORE_CLASS_ID_NJS);
    if (njs != NULL && JS_IsFunction(ctx, njs->hooks[QJS_NJS_HOOK_EXIT])) {
        ret = JS_Call(ctx, njs->hooks[QJS_NJS_HOOK_EXIT], JS_UNDEFINED,
                      0, NULL);

        JS_FreeValue(ctx, njs->hooks[QJS_NJS_HOOK_EXIT]);
        njs->hooks[QJS_NJS_HOOK_EXIT] = JS_UNDEFINED;

        if (JS_IsException(ret)) {
            JS_FreeValue(ctx, obj);
            JS_FreeValue(ctx, global);
            return ret;
        }

        JS_FreeValue(ctx, ret);
    }

done:

    JS_FreeValue(ctx, obj);
    JS_FreeValue(ctx, global);

    return JS_UNDEFINED;
}


static int
qjs_add_intrinsic_njs(JSContext *cx, JSValueConst global)
{
    JSValue  obj, proto;

    if (JS_NewClass(JS_GetRuntime(cx), QJS_CORE_CLASS_ID_NJS,
                    &qjs_njs_class) < 0)
    {
        return -1;
    }

    proto = JS_NewObject(cx);
    if (JS_IsException(proto)) {
        return -1;
    }

    JS_SetPropertyFunctionList(cx, proto, qjs_njs_proto,
                               njs_nitems(qjs_njs_proto));

    JS_SetClassProto(cx, QJS_CORE_CLASS_ID_NJS, proto);

    obj = JS_NewObjectClass(cx, QJS_CORE_CLASS_ID_NJS);
    if (JS_IsException(obj)) {
        return -1;
    }

    if (JS_SetPropertyStr(cx, global, "njs", obj) < 0) {
        return -1;
    }

    return 0;
}


static void
qjs_njs_mark(JSRuntime *rt, JSValueConst val, JS_MarkFunc *mark_func)
{
    unsigned   i;
    qjs_njs_t  *njs;

    njs = JS_GetOpaque(val, QJS_CORE_CLASS_ID_NJS);
    if (njs != NULL) {
        for (i = 0; i < njs_nitems(njs->hooks); i++) {
            JS_MarkValue(rt, njs->hooks[i], mark_func);
        }
    }
}


static void
qjs_njs_finalizer(JSRuntime *rt, JSValue val)
{
    unsigned   i;
    qjs_njs_t  *njs;

    njs = JS_GetOpaque(val, QJS_CORE_CLASS_ID_NJS);
    if (njs != NULL) {
        for (i = 0; i < njs_nitems(njs->hooks); i++) {
            JS_FreeValueRT(rt, njs->hooks[i]);
        }

        js_free_rt(rt, njs);
    }
}


static JSValue
qjs_njs_on(JSContext *ctx, JSValueConst this_val, int argc,
    JSValueConst *argv)
{
    unsigned   i, n;
    qjs_njs_t  *njs;
    njs_str_t  name;

    static const njs_str_t hooks[] = {
        njs_str("exit"),
    };

    njs = JS_GetOpaque(this_val, QJS_CORE_CLASS_ID_NJS);
    if (njs == NULL) {
        njs = js_mallocz(ctx, sizeof(qjs_njs_t));
        if (njs == NULL) {
            return JS_ThrowOutOfMemory(ctx);
        }

        JS_SetOpaque(this_val, njs);
    }

    name.start = (u_char *) JS_ToCStringLen(ctx, &name.length, argv[0]);
    if (name.start == NULL) {
        return JS_EXCEPTION;
    }

    i = 0;
    n = njs_nitems(hooks);

    while (i < n) {
        if (njs_strstr_eq(&name, &hooks[i])) {
            break;
        }

        i++;
    }

    if (i == n) {
        JS_ThrowTypeError(ctx, "unknown hook \"%s\"", name.start);
        JS_FreeCString(ctx, (const char *) name.start);
        return JS_EXCEPTION;
    }

    JS_FreeCString(ctx, (const char *) name.start);

    if (!JS_IsFunction(ctx, argv[1]) && !JS_IsNull(argv[1])) {
        JS_ThrowTypeError(ctx, "callback is not a function or null");
        return JS_EXCEPTION;
    }

    JS_FreeValue(ctx, njs->hooks[i]);
    njs->hooks[i] = JS_DupValue(ctx, argv[1]);

    return JS_UNDEFINED;
}


static JSValue
qjs_process_env(JSContext *ctx, JSValueConst this_val)
{
    int         ret;
    char        **ep;
    JSValue     obj;
    JSAtom      atom;
    JSValue     str, name;
    const char  *entry, *value;

    obj = JS_NewObject(ctx);
    if (JS_IsException(obj)) {
        return JS_EXCEPTION;
    }

    ep = environ;

    while (*ep != NULL) {
        entry = *ep++;

        value = (const char *) njs_strchr(entry, '=');
        if (value == NULL) {
            continue;
        }

        str = JS_UNDEFINED;
        name = JS_NewStringLen(ctx, entry, value - entry);
        if (JS_IsException(name)) {
            goto error;
        }

        value++;

        str = JS_NewStringLen(ctx, value, njs_strlen(value));
        if (JS_IsException(str)) {
            goto error;
        }

        atom = JS_ValueToAtom(ctx, name);
        if (atom == JS_ATOM_NULL) {
            goto error;
        }

        ret = JS_DefinePropertyValue(ctx, obj, atom, str, JS_PROP_C_W_E);
        JS_FreeAtom(ctx, atom);
        if (ret < 0) {
            str = JS_UNDEFINED;
            goto error;
        }

        JS_FreeValue(ctx, name);
    }

    return obj;

error:

    JS_FreeValue(ctx, name);
    JS_FreeValue(ctx, str);
    JS_FreeValue(ctx, obj);

    return JS_EXCEPTION;
}


static JSValue
qjs_process_kill(JSContext *ctx, JSValueConst this_val, int argc,
    JSValueConst *argv)
{
    int                 signo, pid;
    JSValue             ret;
    njs_str_t           name;
    const char          *signal;
    qjs_signal_entry_t  *entry;

    if (JS_ToInt32(ctx, &pid, argv[0]) < 0) {
        return JS_EXCEPTION;
    }

    signo = SIGTERM;

    if (JS_IsNumber(argv[1])) {
        if (JS_ToInt32(ctx, &signo, argv[1]) < 0) {
            return JS_EXCEPTION;
        }

        if (signo < 0 || signo >= NSIG) {
            return JS_ThrowTypeError(ctx, "unknown signal: %d", signo);
        }

    } else {
        signal = JS_ToCString(ctx, argv[1]);
        if (signal == NULL) {
            return JS_EXCEPTION;
        }

        if (njs_strlen(signal) < 3 || memcmp(signal, "SIG", 3) != 0) {
            ret = JS_ThrowTypeError(ctx, "unknown signal: %s", signal);
            JS_FreeCString(ctx, signal);
            return ret;
        }

        name.start = (u_char *) signal + 3;
        name.length = njs_strlen(signal) - 3;

        for (entry = qjs_signals_table; entry->name.length != 0; entry++) {
            if (njs_strstr_eq(&entry->name, &name)) {
                signo = entry->value;
                break;
            }
        }

        if (entry->name.length == 0) {
            ret = JS_ThrowTypeError(ctx, "unknown signal: %s", signal);
            JS_FreeCString(ctx, signal);
            return ret;
        }

        JS_FreeCString(ctx, signal);
    }

    if (kill(pid, signo) < 0) {
        return JS_ThrowTypeError(ctx, "kill failed with (%d:%s)", errno,
                                 strerror(errno));
    }

    return JS_TRUE;
}


static JSValue
qjs_process_pid(JSContext *ctx, JSValueConst this_val)
{
